    for (uint256 i = 0; i < _consensusAddrs.length; i++) {
        IRoninValidator(roninStaking).claimRewards(_consensusAddrs);
    }
    uint256 claimedAmount = address(this).balance;
    _depositRONTo(vault, claimedAmount);
    return claimedAmount;
